  1223→void G1Policy::decide_on_concurrent_start_pause() {
  1224→  // We are about to decide on whether this pause will be a
  1225→  // concurrent start pause.
  1226→
  1227→  // First, collector_state()->in_concurrent_start_gc() should not be already set. We
  1228→  // will set it here if we have to. However, it should be cleared by
  1229→  // the end of the pause (it's only set for the duration of a
  1230→  // concurrent start pause).
  1231→  assert(!collector_state()->in_concurrent_start_gc(), "pre-condition");
  1232→
  1233→  // We should not be starting a concurrent start pause if the concurrent mark
  1234→  // thread is terminating.
  1235→  if (_g1h->concurrent_mark_is_terminating()) {
  1236→    return;
  1237→  }
  1238→
  1239→  if (collector_state()->initiate_conc_mark_if_possible()) {
  1240→    // We had noticed on a previous pause that the heap occupancy has
  1241→    // gone over the initiating threshold and we should start a
  1242→    // concurrent marking cycle.  Or we've been explicitly requested
  1243→    // to start a concurrent marking cycle.  Either way, we initiate
  1244→    // one if not inhibited for some reason.
  1245→
  1246→    GCCause::Cause cause = _g1h->gc_cause();
  1247→    if ((cause != GCCause::_wb_breakpoint) &&
  1248→        ConcurrentGCBreakpoints::is_controlled()) {
  1249→      log_debug(gc, ergo)("Do not initiate concurrent cycle (whitebox controlled)");
  1250→    } else if (!about_to_start_mixed_phase() && collector_state()->in_young_only_phase()) {
  1251→      // Initiate a new concurrent start if there is no marking or reclamation going on.
  1252→      initiate_conc_mark();
  1253→      log_debug(gc, ergo)("Initiate concurrent cycle (concurrent cycle initiation requested)");
  1254→    } else if (_g1h->is_user_requested_concurrent_full_gc(cause) ||
  1255→               (cause == GCCause::_codecache_GC_threshold) ||
  1256→               (cause == GCCause::_codecache_GC_aggressive) ||
  1257→               (cause == GCCause::_wb_breakpoint)) {
  1258→      // Initiate a concurrent start.  A concurrent start must be a young only
  1259→      // GC, so the collector state must be updated to reflect this.
  1260→      collector_state()->set_in_young_only_phase(true);
  1261→      collector_state()->set_in_young_gc_before_mixed(false);
  1262→
  1263→      // We might have ended up coming here about to start a mixed phase with a collection set
  1264→      // active. The following remark might change the change the "evacuation efficiency" of
  1265→      // the regions in this set, leading to failing asserts later.
  1266→      // Since the concurrent cycle will recreate the collection set anyway, simply drop it here.
  1267→      abandon_collection_set_candidates();
  1268→      abort_time_to_mixed_tracking();
  1269→      initiate_conc_mark();
  1270→      log_debug(gc, ergo)("Initiate concurrent cycle (%s requested concurrent cycle)",
  1271→                          (cause == GCCause::_wb_breakpoint) ? "run_to breakpoint" : "user");
  1272→    } else {
  1273→      // The concurrent marking thread is still finishing up the
  1274→      // previous cycle. If we start one right now the two cycles
  1275→      // overlap. In particular, the concurrent marking thread might
  1276→      // be in the process of clearing the next marking bitmap (which
  1277→      // we will use for the next cycle if we start one). Starting a
  1278→      // cycle now will be bad given that parts of the marking
  1279→      // information might get cleared by the marking thread. And we
  1280→      // cannot wait for the marking thread to finish the cycle as it
  1281→      // periodically yields while clearing the next marking bitmap
  1282→      // and, if it's in a yield point, it's waiting for us to
  1283→      // finish. So, at this point we will not start a cycle and we'll
  1284→      // let the concurrent marking thread complete the last one.
  1285→      log_debug(gc, ergo)("Do not initiate concurrent cycle (concurrent cycle already in progress)");
