   282→void G1CollectionSetCandidates::set_candidates_from_marking(G1CollectionSetCandidateInfo* candidate_infos,
   283→                                                            uint num_infos) {
   284→  if (num_infos == 0) {
   285→    log_debug(gc, ergo, cset) ("No regions selected from marking.");
   286→    return;
   287→  }
   288→
   289→  assert(_from_marking_groups.length() == 0, "must be empty at the start of a cycle");
   290→  verify();
   291→
   292→  G1Policy* p = G1CollectedHeap::heap()->policy();
   293→  // During each Mixed GC, we must collect at least G1Policy::calc_min_old_cset_length regions to meet
   294→  // the G1MixedGCCountTarget. For the first collection in a Mixed GC cycle, we can add all regions
   295→  // required to meet this threshold to the same remset group. We are certain these will be collected in
   296→  // the same MixedGC.
   297→  uint group_limit = p->calc_min_old_cset_length(num_infos);
   298→
   299→  uint num_added_to_group = 0;
   300→
   301→  G1CSetCandidateGroup::reset_next_group_id();
   302→  G1CSetCandidateGroup* current = nullptr;
   303→
   304→  current = new G1CSetCandidateGroup();
   305→
   306→  for (uint i = 0; i < num_infos; i++) {
   307→    G1HeapRegion* r = candidate_infos[i]._r;
   308→    assert(!contains(r), "must not contain region %u", r->hrm_index());
   309→    _contains_map[r->hrm_index()] = CandidateOrigin::Marking;
   310→
   311→    if (num_added_to_group == group_limit) {
   312→      if (group_limit != G1OldCSetGroupSize) {
   313→        group_limit = G1OldCSetGroupSize;
   314→      }
   315→
   316→      _from_marking_groups.append(current);
   317→
   318→      current = new G1CSetCandidateGroup();
   319→      num_added_to_group = 0;
   320→    }
   321→    current->add(candidate_infos[i]);
   322→    num_added_to_group++;
   323→  }
   324→
   325→  _from_marking_groups.append(current);
   326→
   327→  assert(_from_marking_groups.num_regions() == num_infos, "Must be!");
   328→
   329→  log_debug(gc, ergo, cset) ("Finished creating %u collection groups from %u regions", _from_marking_groups.length(), num_infos);
   330→  _last_marking_candidates_length = num_infos;
   331→
   332→  verify();
   333→}
