   343→void G1CollectionSetCandidates::remove(G1CSetCandidateGroupList* other) {
   344→  // During removal, we exploit the fact that elements in the marking_regions,
   345→  // retained_regions and other list are sorted by gc_efficiency. Furthermore,
   346→  // all regions in the passed other list are in one of the two other lists.
   347→  //
   348→  // Split original list into elements for the marking list and elements from the
   349→  // retained list.
   350→  G1CSetCandidateGroupList other_marking_groups;
   351→  G1CSetCandidateGroupList other_retained_groups;
   352→
   353→  for (G1CSetCandidateGroup* group : *other) {
   354→    assert(group->length() > 0, "Should not have empty groups");
   355→    // Regions in the same group have the same source (i.e from_marking or retained).
   356→    G1HeapRegion* r = group->region_at(0);
   357→    if (is_from_marking(r)) {
   358→      other_marking_groups.append(group);
   359→    } else {
   360→      other_retained_groups.append(group);
   361→    }
   362→  }
   363→
   364→  _from_marking_groups.remove(&other_marking_groups);
   365→  _retained_groups.remove(&other_retained_groups);
   366→
   367→  other->iterate([&] (G1HeapRegion* r) {
   368→    assert(contains(r), "Must contain region %u", r->hrm_index());
   369→    _contains_map[r->hrm_index()] = CandidateOrigin::Invalid;
   370→  });
   371→
   372→  verify();
   373→}
