   377→  _contains_map[r->hrm_index()] = CandidateOrigin::Retained;
   378→
   379→  G1CSetCandidateGroup* gr = new G1CSetCandidateGroup();
   380→  gr->add(r);
   381→
   382→  _retained_groups.append(gr);
