    32→void G1RemSetTrackingPolicy::update_at_allocate(G1HeapRegion* r) {
    33→  assert(r->is_young() || r->is_humongous() || r->is_old(),
    34→        "Region %u with unexpected heap region type %s", r->hrm_index(), r->get_type_str());
    35→  if (r->is_old()) {
    36→    // By default, do not create remembered set for new old regions.
    37→    r->rem_set()->set_state_untracked();
    38→    return;
    39→  }
    40→  // Always collect remembered set for young regions and for humongous regions.
    41→  // Humongous regions need that for eager reclaim.
    42→  r->rem_set()->set_state_complete();
    43→}
    44→
    45→void G1RemSetTrackingPolicy::update_at_free(G1HeapRegion* r) {
    46→  /* nothing to do */
    47→}
    48→
    49→bool G1RemSetTrackingPolicy::update_humongous_before_rebuild(G1HeapRegion* r) {
    50→  assert(SafepointSynchronize::is_at_safepoint(), "should be at safepoint");
    51→  assert(r->is_starts_humongous(), "Region %u should be Humongous", r->hrm_index());
    52→
    53→  assert(!r->rem_set()->is_updating(), "Remembered set of region %u is updating before rebuild", r->hrm_index());
    54→
    55→  bool selected_for_rebuild = false;
    56→  // Humongous regions containing type-array objs are remset-tracked to
    57→  // support eager-reclaim. However, their remset state can be reset after
    58→  // Full-GC. Try to re-enable remset-tracking for them if possible.
    59→  if (cast_to_oop(r->bottom())->is_typeArray() && !r->rem_set()->is_tracked()) {
    60→    auto on_humongous_region = [] (G1HeapRegion* r) {
    61→      r->rem_set()->set_state_updating();
    62→    };
    63→    G1CollectedHeap::heap()->humongous_obj_regions_iterate(r, on_humongous_region);
    64→    selected_for_rebuild = true;
    65→  }
    66→
    67→  return selected_for_rebuild;
    68→}
