    70→bool G1RemSetTrackingPolicy::update_old_before_rebuild(G1HeapRegion* r) {
    71→  assert(SafepointSynchronize::is_at_safepoint(), "should be at safepoint");
    72→  assert(r->is_old(), "Region %u should be Old", r->hrm_index());
    73→
    74→  assert(!r->rem_set()->is_updating(), "Remembered set of region %u is updating before rebuild", r->hrm_index());
    75→
    76→  bool selected_for_rebuild = false;
    77→
    78→  if (G1CollectionSetChooser::region_occupancy_low_enough_for_evac(r->live_bytes()) &&
    79→      !r->rem_set()->is_tracked()) {
    80→    r->rem_set()->set_state_updating();
    81→    selected_for_rebuild = true;
    82→  }
    83→
    84→  return selected_for_rebuild;
