    87→void G1RemSetTrackingPolicy::update_after_rebuild(G1HeapRegion* r) {
    88→  assert(SafepointSynchronize::is_at_safepoint(), "should be at safepoint");
    89→
    90→  if (r->is_old_or_humongous()) {
    91→    if (r->rem_set()->is_updating()) {
    92→      r->rem_set()->set_state_complete();
    93→    }
    94→    G1CollectedHeap* g1h = G1CollectedHeap::heap();
    95→    // We can drop remembered sets of humongous regions that have a too large remembered set:
    96→    // We will never try to eagerly reclaim or move them anyway until the next concurrent
    97→    // cycle as e.g. remembered set entries will always be added.
    98→    if (r->is_starts_humongous() && !g1h->is_potential_eager_reclaim_candidate(r)) {
    99→      // Handle HC regions with the HS region.
