   103→                                                  "Continues humongous region %u remset should be empty", r->hrm_index());
   104→                                           r->rem_set()->clear(true /* only_cardset */);
   105→                                         });
   106→    }
   107→
   108→    size_t remset_bytes = r->rem_set()->mem_size();
   109→    size_t occupied = 0;
   110→    // per region cardset details only valid if group contains a single region.
   111→    if (r->rem_set()->is_added_to_cset_group() &&
   112→        r->rem_set()->cset_group()->length() == 1 ) {
   113→        G1CardSet *card_set = r->rem_set()->cset_group()->card_set();
   114→        remset_bytes += card_set->mem_size();
   115→        occupied = card_set->occupied();
   116→    }
   117→
   118→    G1ConcurrentMark* cm = G1CollectedHeap::heap()->concurrent_mark();
   119→    log_trace(gc, remset, tracking)("After rebuild region %u "
   120→                                    "(tams " PTR_FORMAT " "
   121→                                    "liveness %zu "
   122→                                    "remset occ %zu "
   123→                                    "size %zu)",
   124→                                    r->hrm_index(),
   125→                                    p2i(cm->top_at_mark_start(r)),
   126→                                    cm->live_bytes(r->hrm_index()),
   127→                                    occupied,
   128→                                    remset_bytes);
   129→  }
   130→}
